import React, { useState, useRef } from "react";
import GoogleMapView from "../components/GoogleMapView";

function Journey() {

  const [origin, setOrigin] = useState("");
  const [destination, setDestination] = useState("");

  const lastLat = useRef(null);
  const lastLon = useRef(null);
  const stopTimer = useRef(null);

  // 🔵 FIND NEAREST POLICE STATION
  const findPoliceStation = async (lat, lon) => {

    const query = `
    [out:json];
    node["amenity"="police"](around:2000,${lat},${lon});
    out;
    `;

    const url =
      "https://overpass-api.de/api/interpreter?data=" +
      encodeURIComponent(query);

    const res = await fetch(url);
    const data = await res.json();

    if (data.elements.length > 0) {

      const police = data.elements[0];

      const policeLat = police.lat;
      const policeLon = police.lon;

      alert("🚓 Nearest police station found! Opening route.");

      window.open(
        `https://www.google.com/maps/dir/${lat},${lon}/${policeLat},${policeLon}`,
        "_blank"
      );

    } else {

      alert("No police station found nearby");

    }

  };


  const startTracking = () => {

    navigator.geolocation.watchPosition(

      async (position) => {

        const lat = position.coords.latitude;
        const lon = position.coords.longitude;

        const res = await fetch(
          `https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lon}`
        );

        const data = await res.json();

        setOrigin(data.display_name);

        // 🔵 CHECK MOVEMENT
        if (lastLat.current !== null) {

          const distance =
            Math.sqrt(
              Math.pow(lat - lastLat.current, 2) +
              Math.pow(lon - lastLon.current, 2)
            );

          if (distance < 0.0001) {

            if (!stopTimer.current) {

              stopTimer.current = setTimeout(() => {

                alert("🚨 Alert: User has stopped moving!");

                // 🔴 CALL POLICE STATION FINDER
                findPoliceStation(lat, lon);

              }, 180000); // 3 minutes

            }

          } else {

            clearTimeout(stopTimer.current);
            stopTimer.current = null;

          }

        }

        lastLat.current = lat;
        lastLon.current = lon;

      },

      (error) => {
        alert("Location tracking failed");
      },

      {
        enableHighAccuracy: true
      }

    );

  };

  return (

    <div className="container">

      <div className="card">

        <h2>Journey Details</h2>

        <input
          type="text"
          placeholder="Current Location"
          value={origin}
          readOnly
        />

        <button onClick={startTracking}>
          Start Live Tracking
        </button>

        <input
          type="text"
          placeholder="Final Destination"
          value={destination}
          onChange={(e) => setDestination(e.target.value)}
        />

      </div>

      <GoogleMapView
        origin={origin}
        destination={destination}
      />

    </div>

  )

}

export default Journey;
